create table am_main.hwas_betriebssystem (
    system_id   number
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 82 cache 20
        noorder nocycle nokeep noscale
    not null enable,
    hst_uid_fk  number not null enable,
    bezeichnung varchar2(200 byte) not null enable,
    bemerkung   varchar2(400 byte),
    inserted    date,
    updated     date,
    inserted_by varchar2(100 byte),
    updated_by  varchar2(100 byte)
)
no inmemory;

alter table am_main.hwas_betriebssystem
    add constraint unique_hst_und_bezeichnung unique ( hst_uid_fk,
                                                       bezeichnung )
        using index enable;

alter table am_main.hwas_betriebssystem add primary key ( system_id )
    using index enable;


